#!/bin/bash
# Apply Hajirai v2: admin redesign (Home page, Analytics tab) + widget UI polish.
# Run from the root of your hajirai project: ~/shopify-apps/hajirai
set -e

if [ ! -d "app/routes" ] || [ ! -d "extensions" ]; then
  echo "ERROR: Run this from the root of your hajirai project (where app/ and extensions/ live)."
  exit 1
fi

echo "Extracting updated files..."
echo "" | base64 -d | tar xz

echo ""
echo "Done. Files updated:"
echo "  - app/routes/app._index.jsx           (new Home page)"
echo "  - app/routes/app.analytics.jsx        (NEW — Analytics tab)"
echo "  - app/routes/app.jsx                  (NavMenu with Home + Analytics)"
echo "  - app/routes/app.api-keys.jsx         (polished)"
echo "  - app/routes/app.knowledge.jsx        (polished)"
echo "  - extensions/.../hajirai-chat-widget.css  (widget polish)"
echo "  - extensions/.../hajirai_chat.liquid      (CTA grid fix)"
echo ""
echo "Next steps:"
echo "  1. Restart 'shopify app dev'"
echo "  2. Test the admin (should land on Home now)"
echo "  3. Test the widget on your storefront"
echo "  4. git add -A && git commit -m 'Admin redesign + widget polish' && git push"
